class Task:
    def __init__(self, title):
        self.title = title
        self.done = False

    def mark_done(self):
        self.done = True

    def summary(self):
        return f"{self.title} - done: {self.done}"


title = input()
command = input()
task = Task(title)

if command == "done":
    task.mark_done()

print(task.summary())

