class Task:
    def __init__(self, title):
        self.title = title
        self.done = False

    def mark_done(self):
        self.done = True

    def summary(self):
        return f"{self.title} - done: {self.done}"


def count_done(tasks):
    total = 0
    for task in tasks:
        if task.done:
            total += 1
    return total


title1 = input()
title2 = input()
title3 = input()

tasks = [Task(title1), Task(title2), Task(title3)]
tasks[0].mark_done()
tasks[2].mark_done()

print(count_done(tasks))

